#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* Simple open‑addressing hash set for 32‑bit integers */
#define HSIZE 1048576  // power of two, > 2 * max segment length
static unsigned int keys[HSIZE];
static char used[HSIZE];
static unsigned int mask = HSIZE - 1;

static void hs_clear() {
    memset(used, 0, sizeof(used));
}

static unsigned int hs_hash(unsigned int x) {
    x ^= x >> 16;
    x *= 0x7feb352dU;
    x ^= x >> 15;
    return x & mask;
}

static int hs_contains(unsigned int x) {
    unsigned int h = hs_hash(x);
    while (used[h]) {
        if (keys[h] == x) return 1;
        h = (h + 1) & mask;
    }
    return 0;
}

static void hs_insert(unsigned int x) {
    unsigned int h = hs_hash(x);
    while (used[h]) {
        if (keys[h] == x) return; // already present
        h = (h + 1) & mask;
    }
    used[h] = 1;
    keys[h] = x;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        unsigned int cur = 0;
        int ans = 0;
        hs_clear();
        hs_insert(0);
        for (int i = 0; i < N; ++i) {
            unsigned int a; scanf("%u", &a);
            cur ^= a;
            if (hs_contains(cur)) {
                ++ans;
                hs_clear();
                hs_insert(cur ^ a); // previous prefix xor
                hs_insert(cur);
            } else {
                hs_insert(cur);
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

