#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        cur = 0
        ans = 0
        seen = {0}
        for _ in range(N):
            a = int(next(it))
            cur ^= a
            if cur in seen:
                ans += 1
                seen.clear()
                seen.add(cur ^ a)  # previous prefix xor
                seen.add(cur)
            else:
                seen.add(cur)
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

